import bisect
class Solution:
    def countRectangles(self, rectangles, points):
        buckets = [[] for _ in range(101)]
        for l, h in rectangles:
            buckets[h].append(l)
        for h in range(101):
            buckets[h].sort()
        res = []
        for x, y in points:
            total = 0
            for h in range(y, 101):
                arr = buckets[h]
                idx = bisect.bisect_left(arr, x)
                total += len(arr) - idx
            res.append(total)
        return res

