var countRectangles = function(rectangles, points) {
    const buckets = Array.from({ length: 101 }, () => []);
    for (const [l, h] of rectangles) buckets[h].push(l);
    for (let h = 0; h <= 100; h++) buckets[h].sort((a, b) => a - b);
    const lowerBound = (arr, x) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < x) lo = mid + 1; else hi = mid;
        }
        return lo;
    };
    const res = [];
    for (const [x, y] of points) {
        let total = 0;
        for (let h = y; h <= 100; h++) {
            const arr = buckets[h];
            total += arr.length - lowerBound(arr, x);
        }
        res.push(total);
    }
    return res;
};
